import { IMAGE_ALT } from "../../../constants/strings";
import { isMobile } from "../../../utils/general";
import "../../../styles/main/Photo.css";

const PhotoModal = ({ openModal, imageSrc }) => {
  const handleClick = () => {
    if (isMobile()) {
      return;
    }
    openModal();
  };

  return (
    <div onClick={handleClick}>
      <img src={imageSrc} alt={IMAGE_ALT} className="photo" />
    </div>
  );
};

export default PhotoModal;
