import Bar from "./Bar";
import "../../../styles/toolbar/bar-chart.css";

const BarChart = ({ resultDistribution }) => {
  const maxResult = Math.max(...resultDistribution);

  return (
    <div className="bar-chart-container">
      <div className="bars-container">
        {resultDistribution.map((result, index) => (
          <Bar
            label={index + 1}
            result={result}
            maxResult={maxResult}
            key={index}
          />
        ))}
      </div>
      <div className="chart-label">Number of Guesses</div>
    </div>
  );
};

export default BarChart;
