import { useContext } from "react";
import { ApiContext } from "../../contexts/ApiContext";
import Guess from "./Guess";

const AllGuesses = () => {
  const { loadingPhoto, loadingPhotosList, userGuesses } =
    useContext(ApiContext);

  if (loadingPhoto || loadingPhotosList) return null;

  return (
    <div className="all-guesses-container">
      {userGuesses.map(
        ({ city, countryCode, flag, bearing, distance }, index) => (
          <Guess
            city={city}
            countryCode={countryCode}
            flag={flag}
            bearing={bearing}
            distance={distance}
            key={index}
          />
        )
      )}
    </div>
  );
};

export default AllGuesses;
