import { MAX_CITY_NAME_LENGTH } from "../constants/general";
import { KM, MI } from "../constants/strings";
import { ALL_COUNTRIES } from "../data/all-countries";

export const isMobile = () =>
  /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(
    navigator.userAgent
  );

export const removePlayed = (photosList, userRecord) => {
  if (!userRecord) return photosList;

  let photosListCopy = [...photosList];
  for (let record of userRecord) {
    const photoIndex = photosListCopy.findIndex(({ id }) => id === record.id);
    if (photoIndex >= 0) {
      photosListCopy = [
        ...photosListCopy.slice(0, photoIndex),
        ...photosListCopy.slice(photoIndex + 1),
      ];
    }
  }
  return photosListCopy;
};

export const extractCountryProperties = (countryName) => {
  const countryIndex = ALL_COUNTRIES.findIndex(
    (country) => country.name === countryName
  );
  const country = ALL_COUNTRIES[countryIndex];
  const { flag, countryCode } = country;
  return { countryCode, flag };
};

const trimCityName = (cityName, maxLength = MAX_CITY_NAME_LENGTH) => {
  return cityName.length > maxLength
    ? cityName.slice(0, maxLength) + "."
    : cityName;
};

export const formatLocationText = (city, countryCode) => {
  if (!city) return "";
  return `${trimCityName(city)}, ${countryCode}`;
};

export const addUnitToDistance = (distance, unit) => {
  if (distance === 0 && unit === KM) return "0km";
  if (distance === 0 && unit === MI) return "0mi";
  if (!distance) return "";
  const formattedDistance = distance.toLocaleString();
  return `${formattedDistance}${unit}`;
};

export const convertKmToMiles = (km) => Math.round(km * 0.621371192);

export const generateInt = (min, max) => {
  return min + Math.floor(Math.random() * (max - min));
};

const capitalizeWord = (word) => {
  const splitWord = word.split("");
  const formattedWord = splitWord.map((letter, index) =>
    index === 0 ? letter.toUpperCase() : letter.toLowerCase()
  );
  return formattedWord.join("");
};

export const formatyCityName = (cityName) => {
  const splitName = cityName.split(" ");
  const formattedArray = splitName.map((word) => capitalizeWord(word));
  return formattedArray.join(" ").trim();
};

export const countUnique = (array) => new Set(array).size;
