import { useEffect } from "react";
import { calculateBearing, calculateDistance } from "../../../utils/geography";
import { extractCountryProperties } from "../../../utils/general";
import { SET_GUESS } from "../../../types";
import {
  dispatchDistances,
  reverseDispatchDistances,
} from "./dispatch-distance";

export const useSubmitValidCity = (state) => {
  const {
    dispatch,
    submitClicked,
    cityDetailsLoading,
    cityDetails,
    selectedCountry,
    selectedCity,
    numGuesses,
    photosList,
    photoIndex,
    lastDistance,
  } = state;
  const displayedCity = photosList[photoIndex];

  useEffect(() => {
    const guessedCity = cityDetails.at(0);
    const { longitude, latitude } = displayedCity;
    const correctCoordinates = { longitude, latitude };
    const validCityEntered =
      submitClicked && !cityDetailsLoading && cityDetails.length;

    if (validCityEntered) {
      const finalDistance = calculateDistance(correctCoordinates, guessedCity);
      const answerCorrect = finalDistance === 0;
      const countryProps = extractCountryProperties(selectedCountry?.value);
      const bearing = calculateBearing(correctCoordinates, guessedCity);
      const { id: photoId } = photosList[photoIndex];

      dispatch({
        type: SET_GUESS,
        payload: {
          city: selectedCity,
          ...countryProps,
          distance: answerCorrect ? lastDistance : 0,
          bearing: answerCorrect ? "" : bearing,
        },
      });

      if (answerCorrect) {
        reverseDispatchDistances(dispatch, lastDistance, numGuesses, photoId);
      } else {
        dispatchDistances(
          dispatch,
          finalDistance,
          numGuesses,
          displayedCity,
          photoId
        );
      }
    }
  }, [
    dispatch,
    photosList,
    photoIndex,
    lastDistance,
    submitClicked,
    cityDetailsLoading,
    cityDetails,
    selectedCountry,
    selectedCity,
    numGuesses,
    displayedCity,
  ]);
};
