const BASE_URL = "https://papaya-kheer-605627.netlify.app";
const ALL_RECORDS = ".netlify/functions/fetch-records";
const PHOTOS_RESOURCE = ".netlify/functions/fetch-image";
const CITY_DETAILS_RESOURCE = ".netlify/functions/fetch-city-details";

export const getPhotosList = () => {
  return fetch(`${BASE_URL}/${ALL_RECORDS}`);
};

export const getPhoto = (photoId) => {
  return fetch(`${BASE_URL}/${PHOTOS_RESOURCE}?photoId=${photoId}`);
};

export const getCityDetails = (city, country) => {
  return fetch(
    `${BASE_URL}/${CITY_DETAILS_RESOURCE}?city=${city}&country=${country}`
  );
};
