import { NUM_GUESSES, USER_GUESSES } from "../constants/general";
import {
  INCREMENT_PHOTO_INDEX,
  SET_LOADING_PHOTO,
  SET_LOADING_IS_SLOW,
  SET_DISPLAYED_PHOTO,
  SET_LIMITED_REACHED,
  SET_PHOTOS_LIST,
  SET_SELECTED_CITY,
  SET_SELECTED_COUNTRY,
  SET_CITY_DETAILS,
  SET_CITY_DETAILS_LOADING,
  SET_CITY_DETAILS_FETCH_ERROR,
  SET_GUESS,
  SET_GUESS_DISTANCE,
  FINALIZE_GUESS,
  RESET_GUESSES,
  SET_SUBMIT_CLICKED,
  SET_DISTANCE_BEING_UPDATED,
  SET_CITY_DETAILS_NOT_LOADING,
  SET_NUM_RECORDS,
} from "../types";
import { generateInt } from "../utils/general";

export const apiReducer = (state, action) => {
  const { type, payload } = action;
  switch (type) {
    case SET_PHOTOS_LIST: {
      return {
        ...state,
        photosList: payload,
        loadingPhotosList: false,
        loadingPhoto: true,
      };
    }
    case SET_DISPLAYED_PHOTO: {
      return {
        ...state,
        loadingPhoto: false,
        displayedPhoto: payload,
        loadingIsSlow: false,
      };
    }
    case SET_LOADING_PHOTO: {
      return { ...state, loadingPhoto: true };
    }
    case SET_LOADING_IS_SLOW:
      return { ...state, loadingIsSlow: true };
    case INCREMENT_PHOTO_INDEX:
      return { ...state, photoIndex: state.photoIndex + 1 };
    case SET_LIMITED_REACHED:
      return { ...state, limitReached: true };
    case SET_SELECTED_CITY:
      return { ...state, selectedCity: payload };
    case SET_SELECTED_COUNTRY:
      return { ...state, selectedCountry: payload, submitClicked: false };
    case SET_CITY_DETAILS:
      return { ...state, cityDetails: payload };
    case SET_CITY_DETAILS_LOADING:
      return { ...state, cityDetailsLoading: true, cityBeingLoaded: payload };
    case SET_CITY_DETAILS_NOT_LOADING: {
      if (payload === state.cityBeingLoaded) {
        return { ...state, cityDetailsLoading: false };
      } else {
        return { ...state };
      }
    }
    case SET_CITY_DETAILS_FETCH_ERROR:
      return { ...state, cityDetailsFetchError: payload };
    case SET_GUESS: {
      const userGuessesCopy = [...state.userGuesses];
      userGuessesCopy[state.numGuesses] = payload;
      return {
        ...state,
        userGuesses: [...userGuessesCopy],
        distanceBeingUpdated: true,
      };
    }
    case SET_GUESS_DISTANCE: {
      const userGuessesCopy = [...state.userGuesses];
      const currentGuess = userGuessesCopy[state.numGuesses];
      currentGuess.distance = payload;
      return { ...state, userGuesses: [...userGuessesCopy] };
    }
    case FINALIZE_GUESS:
      return {
        ...state,
        numGuesses: payload ? state.numGuesses + 1 : NUM_GUESSES,
        selectedCity: "",
        selectedCountry: null,
        cityDetails: [],
        submitClicked: false,
        cityBeingLoaded: "",
        lastDistance: payload || generateInt(100, 1000),
      };
    case RESET_GUESSES:
      return {
        ...state,
        numGuesses: 0,
        userGuesses: USER_GUESSES,
        lastDistance: generateInt(100, 1000),
      };
    case SET_SUBMIT_CLICKED:
      return { ...state, submitClicked: payload };
    case SET_DISTANCE_BEING_UPDATED:
      return { ...state, distanceBeingUpdated: payload };
    case SET_NUM_RECORDS: {
      return { ...state, numRecords: { ...payload } };
    }
    default:
      return state;
  }
};
