import React from "react";
import { AiFillCheckCircle, AiFillCloseCircle } from "react-icons/ai";

export const determineAdditionalClass = (correct, darkMode) => {
  if (correct) {
    return darkMode ? `correct-dark-mode` : `correct-light-mode`;
  } else {
    return darkMode ? `incorrect-dark-mode` : `incorrect-light-mode`;
  }
};

export const determineButtonClasses = (
  additionalClass,
  revealAnswer,
  choice,
  correctAnswer,
  darkMode,
  disableChoices
) => {
  let classNames = "choice";
  if (additionalClass) {
    classNames += ` ${additionalClass}`;
  }
  if (revealAnswer && choice === correctAnswer) {
    darkMode
      ? (classNames += " reveal-correct-dark-mode")
      : (classNames += " reveal-correct-light-mode");
  }
  if (disableChoices) {
    classNames += " disabled-button";
  }
  return classNames;
};

export const showIcon = (additionalClass) => {
  if (!additionalClass) {
    return null;
  }
  if (additionalClass.indexOf("incorrect") !== -1) {
    return <AiFillCloseCircle className="icon" color="#A53B3B" />;
  } else if (additionalClass.indexOf("correct") !== -1) {
    return <AiFillCheckCircle className="icon" color="#228B22" />;
  }
};
