import SettingsSection from "./SettingsSection";
import Separator from "./Separator";
import "../../../styles/toolbar/settings-modal.css";
import { useContext } from "react";
import {
  SET_SELECTED_CITY,
  SET_SELECTED_COUNTRY,
  TOGGLE_DARK_MODE,
  TOGGLE_DISTANCES_IN_MILES,
  TOGGLE_HARD_MODE,
} from "../../../types";
import TwitterHandle from "./TwitterHandle";
import AboutGame from "./AboutGame";
import { USER_SETTINGS } from "../../../constants/strings";
import { SettingsContext } from "../../../contexts/SettingsContext";
import { ApiContext } from "../../../contexts/ApiContext";

const SettingsContent = () => {
  const { dispatch: apiDispatch } = useContext(ApiContext);
  const currentSettings = JSON.parse(localStorage.getItem(USER_SETTINGS));
  const { dispatch, hardMode, darkMode, distancesInMiles } =
    useContext(SettingsContext);

  const toggleHardMode = (event) => {
    const updatedMode = !event.target.checked;
    const updatedSettings = {
      ...currentSettings,
      settingsModalOpen: false,
      hardMode: updatedMode,
    };
    dispatch({ type: TOGGLE_HARD_MODE, payload: updatedMode });
    apiDispatch({ type: SET_SELECTED_CITY, payload: "" });
    apiDispatch({ type: SET_SELECTED_COUNTRY, payload: null });
    localStorage.setItem(USER_SETTINGS, JSON.stringify(updatedSettings));
  };

  const toggleDarkMode = (event) => {
    const updatedMode = event.target.checked;
    const updatedSettings = {
      ...currentSettings,
      settingsModalOpen: false,
      darkMode: updatedMode,
    };
    dispatch({ type: TOGGLE_DARK_MODE, payload: updatedMode });
    localStorage.setItem(USER_SETTINGS, JSON.stringify(updatedSettings));
  };

  const toggleDistancesInMiles = (event) => {
    const updatedMode = event.target.checked;
    const updatedSettings = {
      ...currentSettings,
      settingsModalOpen: false,
      distancesInMiles: updatedMode,
    };
    dispatch({ type: TOGGLE_DISTANCES_IN_MILES, payload: updatedMode });
    localStorage.setItem(USER_SETTINGS, JSON.stringify(updatedSettings));
  };

  return (
    <div className="settings-container">
      <div className="settings-heading">SETTINGS</div>
      <div className="settings-details">
        <SettingsSection
          title="Easy Mode"
          description="Easy Mode = Multiple choice"
          checked={!hardMode}
          onChange={toggleHardMode}
          isSwitch
        />
        <Separator />
        <SettingsSection
          title="Dark Mode"
          checked={darkMode}
          onChange={toggleDarkMode}
          isSwitch
        />
        <Separator />
        <SettingsSection
          title="Display Distances in Miles"
          description="Default = Kilometers"
          checked={distancesInMiles}
          onChange={toggleDistancesInMiles}
          isSwitch
        />
        <Separator />
        <SettingsSection
          title="Contact"
          description="Feedback, bugs, compliments"
          isSwitch={false}
          value={<TwitterHandle />}
        />
        <Separator />
        <AboutGame />
      </div>
    </div>
  );
};

export default SettingsContent;
