import { useContext } from "react";
import { SettingsContext } from "../../../contexts/SettingsContext";
import "../../../styles/select/city-not-found.css";

const CityNotFound = ({ cityNotFound }) => {
  const { darkMode } = useContext(SettingsContext);

  return (
    <div
      className={`city-not-found-container ${
        darkMode
          ? "city-not-found-container-dark-mode"
          : "city-not-found-container-light-mode"
      }`}
    >
      {cityNotFound ? <span>City not found!</span> : <span>&#8203;</span>}
    </div>
  );
};

export default CityNotFound;
