import { useContext } from "react";
import "../../../styles/toolbar/info-modal.css";
import { SettingsContext } from "../../../contexts/SettingsContext";
import { KILOMETERS, KM, MI, MILES } from "../../../constants/strings";
import {
  EXAMPLE_DISTANCE_KM,
  EXAMPLE_DISTANCE_MI,
} from "../../../constants/general";

const InfoContent = () => {
  const { distancesInMiles, darkMode } = useContext(SettingsContext);
  const distance = distancesInMiles ? EXAMPLE_DISTANCE_MI : EXAMPLE_DISTANCE_KM;
  const formattedDistance = distancesInMiles
    ? `${distance.toLocaleString()}${MI}`
    : `${distance.toLocaleString()}${KM}`;
  const unit = distancesInMiles ? MILES : KILOMETERS;

  return (
    <div className="info-container">
      <div className="info-heading">HOW TO PLAY</div>
      <div className="info-details">
        <ul>
          <li>Guess the city in the photo.</li>
          <li>Click on a photo to zoom in.</li>
          <li className="list-heading">HARD MODE</li>
          <li>You have four chances to guess the correct city.</li>
          <li>
            After each incorrect guess, you will be shown the distance between
            your guess and the correct city, and an arrow indicating in which
            direction the correct city is:
          </li>
          <li className="list-heading">
            <div
              className={`guess-example ${
                darkMode
                  ? "modal-example-dark-mode"
                  : "modal-example-light-mode"
              }`}
            >
              <div>🇯🇴 Amman, JO</div>
              <div>{formattedDistance} ←</div>
            </div>
          </li>
          <li>
            In the example above, the user's guess is Amman, Jordan, and the
            correct city is {distance.toLocaleString()} {unit} to the west of
            Amman.
          </li>
          <li>
            After answering, click the close button to load the next question:
          </li>
          <li className="list-heading">
            <div
              className={`toast-example ${
                darkMode
                  ? "modal-example-dark-mode"
                  : "modal-example-light-mode"
              }`}
            >
              <div>🎉</div>
              <div>Well done!</div>
              <div className="close-button-example">✕</div>
            </div>
          </li>
          <li className="list-heading">EASY MODE</li>
          <li>
            You are given four multiple choice options, and have one chance to
            guess the correct city.
          </li>
        </ul>
      </div>
    </div>
  );
};

export default InfoContent;
