import { useContext } from "react";
import Select from "react-select";
import { FORMATTED_COUNTRIES } from "../../../data/all-countries";
import {
  COUNTRY_SELECT_PLACEHOLDER,
  STANDARD,
} from "../../../constants/strings";
import { ApiContext } from "../../../contexts/ApiContext";
import { SET_CITY_DETAILS_LOADING, SET_SELECTED_COUNTRY } from "../../../types";
import { CITY_NAME_MIN_LENGTH } from "../../../constants/general";
import { SettingsContext } from "../../../contexts/SettingsContext";
import { customStyles } from "../../../constants/select-dropdown-custom-styles";
import "../../../styles/select/country-select.css";

const CountrySelect = ({ setCityNotFound, setCityInputFocus, disabled }) => {
  const { selectedCountry, selectedCity, dispatch } = useContext(ApiContext);
  const { darkMode } = useContext(SettingsContext);

  const handleChange = (selection) => {
    setCityNotFound(false);
    setCityInputFocus(STANDARD);
    dispatch({ type: SET_SELECTED_COUNTRY, payload: selection });
    if (selectedCity.length >= CITY_NAME_MIN_LENGTH && selection?.value) {
      dispatch({
        type: SET_CITY_DETAILS_LOADING,
        payload: `${selectedCity}-${selection.value}`,
      });
    }
  };

  return (
    <div className="country-select-container">
      <Select
        options={FORMATTED_COUNTRIES}
        openMenuOnClick={false}
        isClearable
        placeholder={COUNTRY_SELECT_PLACEHOLDER}
        menuPlacement="top"
        onChange={handleChange}
        value={selectedCountry}
        isDisabled={disabled}
        styles={darkMode ? customStyles : {}}
      />
    </div>
  );
};

export default CountrySelect;
