import Stat from "./Stat";

const StatsSection = ({ heading, stats }) => {
  return (
    <div>
      <p className="stats-section-heading">{heading}</p>
      <div className="stats-section-container">
        {stats.map(({ stat, descriptor }, index) => (
          <Stat stat={stat} descriptor={descriptor} key={index} />
        ))}
      </div>
    </div>
  );
};

export default StatsSection;
