import { useContext, useEffect } from "react";
import "./App.css";
import MainBody from "./components/main/MainBody";
import { SettingsContext } from "./contexts/SettingsContext";
import Toolbar from "./components/toolbar/Toolbar";
import { USER_SETTINGS } from "./constants/strings";
import { INITIAL_SETTINGS } from "./constants/initial-state";
import UserResponse from "./components/UserResponse";
import SettingsModal from "./components/toolbar/settings-modal/SettingsModal";
import InfoModal from "./components/toolbar/info-modal/InfoModal";
import StatsModal from "./components/toolbar/stats-modal/StatsModal";

const App = () => {
  const {
    darkMode,
    dispatch,
    settingsModalOpen,
    infoModalOpen,
    statsModalOpen,
  } = useContext(SettingsContext);

  useEffect(() => {
    const savedSettings = localStorage.getItem(USER_SETTINGS);
    if (!savedSettings) {
      localStorage.setItem(USER_SETTINGS, JSON.stringify(INITIAL_SETTINGS));
    }
  }, []);

  return (
    <div className={`App ${darkMode ? "dark-mode" : "light-mode"}`}>
      <Toolbar />
      <MainBody />
      <UserResponse />
      {settingsModalOpen && <SettingsModal dispatch={dispatch} />}
      {infoModalOpen && <InfoModal dispatch={dispatch} />}
      {statsModalOpen && <StatsModal dispatch={dispatch} />}
    </div>
  );
};

export default App;
