import { useContext } from "react";
import Message from "./state-components/Message";
import Loader from "./state-components/Loader";
import Photo from "./Photo";
import { ApiContext } from "../../contexts/ApiContext";
import ColorRingLoader from "./state-components/ColorRingLoader";

const MainBody = () => {
  const { displayedPhoto, loadingPhoto, loadingPhotosList, limitReached } =
    useContext(ApiContext);

  if (limitReached) {
    return (
      <Message
        messageEmoji="😐"
        messageText="There are no more questions to show. More to come soon!"
      />
    );
  }

  if (loadingPhotosList) {
    return <ColorRingLoader />;
  }

  if (loadingPhoto) {
    return <Loader />;
  }

  return <Photo displayedPhoto={displayedPhoto} />;
};

export default MainBody;
