import { NUM_GUESSES } from "../constants/general";

const extractHardMode = (userRecord) =>
  userRecord.filter((record) => record.hardMode);

const extractEasyMode = (userRecord) =>
  userRecord.filter((record) => !record.hardMode);

const computeCorrect = (userRecord) => {
  const numCorrect = userRecord.filter((record) => record.correct).length;
  const numPlayed = userRecord.length;
  const percentageCorrect = Math.round((numCorrect / numPlayed) * 100) || "0";
  return { numPlayed, numCorrect, percentageCorrect };
};

export const formatResults = (userRecord, hardMode = null) => {
  let recordToParse = userRecord;
  if (hardMode === true) {
    recordToParse = extractHardMode(userRecord);
  } else if (hardMode === false) {
    recordToParse = extractEasyMode(userRecord);
  }
  const { numPlayed, numCorrect, percentageCorrect } =
    computeCorrect(recordToParse);
  return [
    { stat: numPlayed, descriptor: "Played" },
    { stat: numCorrect, descriptor: "Correct" },
    { stat: `${percentageCorrect}%`, descriptor: "Score" },
  ];
};

export const extractHardModeResults = (userRecord) => {
  const hardModeRecord = extractHardMode(userRecord);
  const hardModeResults = new Array(NUM_GUESSES)
    .fill()
    .map((emptyElement, index) => index + 1);
  return hardModeResults.map(
    (numGuesses) =>
      hardModeRecord.filter(
        (record) => record.correct && record.numGuesses === numGuesses
      ).length
  );
};
