import { useContext, useState } from "react";
import { ApiContext } from "../../contexts/ApiContext";
import { SettingsContext } from "../../contexts/SettingsContext";
import {
  DISABLE_CHOICES,
  ENABLE_CHOICES,
  HIDE_ANSWER,
  INCREMENT_PHOTO_INDEX,
  RESET_GUESSES,
  REVEAL_ANSWER,
  SET_LOADING_PHOTO,
} from "../../types";
import {
  determineAdditionalClass,
  determineButtonClasses,
  showIcon,
} from "../../utils/styles";
import "../../styles/choices/Choice.css";
import { USER_RECORD, USER_SETTINGS } from "../../constants/strings";

const Choice = ({ choice, photoId }) => {
  const [additionalClass, setAdditionalClass] = useState(null);
  const {
    dispatch: apiDispatch,
    photosList,
    photoIndex,
  } = useContext(ApiContext);
  const {
    dispatch: settingsDispatch,
    darkMode,
    revealAnswer,
    disableChoices,
  } = useContext(SettingsContext);

  const updateUserSettings = () => {
    const currentSettings = JSON.parse(localStorage.getItem(USER_SETTINGS));
    const updatedSettings = {
      ...currentSettings,
      infoModalOpen: false,
      statsModalOpen: true,
    };
    localStorage.setItem(USER_SETTINGS, JSON.stringify(updatedSettings));
  };

  const { correct: correctAnswer } = photosList[photoIndex] || {};
  const currentRecord = JSON.parse(localStorage.getItem(USER_RECORD)) || [];

  const handleClick = () => {
    const moveToNextPhoto = () => {
      setAdditionalClass(null);
      settingsDispatch({ type: ENABLE_CHOICES });
      apiDispatch({ type: INCREMENT_PHOTO_INDEX });
      apiDispatch({ type: SET_LOADING_PHOTO });
    };

    settingsDispatch({ type: DISABLE_CHOICES });
    apiDispatch({ type: RESET_GUESSES });
    updateUserSettings();

    if (choice === correctAnswer) {
      setAdditionalClass(determineAdditionalClass(true, darkMode));
      setTimeout(() => moveToNextPhoto(), 1000);
      currentRecord.push({ id: photoId, correct: true, hardMode: false });
      localStorage.setItem(USER_RECORD, JSON.stringify(currentRecord));
    } else {
      setAdditionalClass(determineAdditionalClass(false, darkMode));
      setTimeout(() => {
        settingsDispatch({ type: REVEAL_ANSWER });
      }, 750);
      setTimeout(() => {
        settingsDispatch({ type: HIDE_ANSWER });
        moveToNextPhoto();
      }, 2500);
      currentRecord.push({ id: photoId, correct: false, hardMode: false });
      localStorage.setItem(USER_RECORD, JSON.stringify(currentRecord));
    }
  };

  return (
    <button
      className={determineButtonClasses(
        additionalClass,
        revealAnswer,
        choice,
        correctAnswer,
        darkMode,
        disableChoices
      )}
      disabled={disableChoices}
      onClick={handleClick}
    >
      <div>{choice}</div>
      {showIcon(additionalClass)}
    </button>
  );
};

export default Choice;
