import { ESCAPE, IMAGE_ALT } from "../../../constants/strings";
import "../../../styles/main/Photo.css";

const PhotoModalContent = ({ closeModal, imageSrc }) => {
  document.onkeydown = (event) => {
    if (event.key === ESCAPE) {
      closeModal();
    }
  };

  return (
    <div className="modal" onClick={closeModal}>
      <div className="modal-content">
        <img src={imageSrc} alt={IMAGE_ALT} className="photo-in-modal" />
      </div>
    </div>
  );
};

export default PhotoModalContent;
