import { useContext } from "react";
import { SettingsContext } from "../../../contexts/SettingsContext";

const Bar = ({ label, result, maxResult }) => {
  const { darkMode } = useContext(SettingsContext);

  // barHeight as % of div height
  const barHeight = 0.7;
  const height = `${Math.round((result / maxResult) * 100 * barHeight)}%`;

  return (
    <div
      className={`bar-container ${
        darkMode ? "bar-container-dark-mode" : "bar-container-light-mode"
      }`}
    >
      <div className="bar-value">{result}</div>
      <div className="bar" style={{ height }} />
      <div className="bar-label">{label}</div>
    </div>
  );
};

export default Bar;
