import { useContext } from "react";
import { SettingsContext } from "../../../contexts/SettingsContext";
import "../../../styles/main/AttributionText.css";

const AttributionTextLink = ({ link, text }) => {
  const { darkMode } = useContext(SettingsContext);

  return (
    <a
      href={link}
      target="_blank"
      rel="noreferrer noopener"
      className={`attribution-link ${
        darkMode ? "attribution-link-dark-mode" : "attribution-link-light-mode"
      }`}
    >
      {text}
    </a>
  );
};

export default AttributionTextLink;
