import { useContext, useEffect, useRef } from "react";
import {
  CITY_INPUT_PLACEHOLDER,
  ERROR,
  STANDARD,
} from "../../../constants/strings";
import { ApiContext } from "../../../contexts/ApiContext";
import {
  SET_SELECTED_CITY,
  SET_SELECTED_COUNTRY,
  SET_SUBMIT_CLICKED,
} from "../../../types";
import { formatyCityName } from "../../../utils/general";
import { SettingsContext } from "../../../contexts/SettingsContext";
import "../../../styles/select/city-input.css";
import { INPUT_REF_FOCUS_TIMEOUT } from "../../../constants/general";

const CityInput = ({
  cityInputFocus,
  setCityInputFocus,
  setCityNotFound,
  disabled,
}) => {
  const {
    selectedCity,
    cityDetailsLoading,
    cityDetails,
    dispatch,
    submitClicked,
  } = useContext(ApiContext);
  const { darkMode } = useContext(SettingsContext);
  const inputRef = useRef();

  const handleChange = (event) => {
    setCityInputFocus(STANDARD);
    setCityNotFound(false);
    dispatch({ type: SET_SELECTED_CITY, payload: event.target.value });
    dispatch({ type: SET_SELECTED_COUNTRY, payload: null });
  };

  useEffect(() => {
    if (submitClicked && !cityDetailsLoading && !cityDetails.length) {
      setCityInputFocus(ERROR);
      setCityNotFound(true);
      dispatch({ type: SET_SUBMIT_CLICKED, payload: false });
      setTimeout(() => inputRef.current.focus(), INPUT_REF_FOCUS_TIMEOUT);
    }
  }, [
    submitClicked,
    cityDetailsLoading,
    cityDetails,
    setCityInputFocus,
    setCityNotFound,
    dispatch,
  ]);

  const determineClassName = (disabled, focused, darkMode) => {
    let className = "city-input";
    let darkModeClass = darkMode
      ? "city-input-dark-mode"
      : "city-input-light-mode";
    let disabledClass = "";
    let focusedClass = "";
    if (focused === STANDARD && !darkMode) {
      focusedClass = "city-input-light-mode-standard";
    } else if (focused === ERROR && !darkMode) {
      focusedClass = "city-input-light-mode-error";
    }
    if (disabled && darkMode) {
      disabledClass = "city-input-dark-mode-disabled";
    } else if (disabled && !darkMode) {
      disabledClass = "city-input-light-mode-disabled";
    }
    return `${className} ${darkModeClass} ${focusedClass} ${disabledClass}`;
  };

  return (
    <div className="city-input-container">
      <input
        type="text"
        placeholder={CITY_INPUT_PLACEHOLDER}
        className={determineClassName(disabled, cityInputFocus, darkMode)}
        value={selectedCity}
        onChange={handleChange}
        ref={inputRef}
        disabled={disabled}
        onBlur={(event) => {
          const formattedName = formatyCityName(event.target.value);
          dispatch({ type: SET_SELECTED_CITY, payload: formattedName });
        }}
      />
    </div>
  );
};

export default CityInput;
