import { useContext } from "react";
import { IoIosStats, IoMdSettings } from "react-icons/io";
import { AiFillInfoCircle } from "react-icons/ai";
import { ApiContext } from "../../contexts/ApiContext";
import "../../styles/toolbar/toolbar.css";
import { SettingsContext } from "../../contexts/SettingsContext";
import {
  TOGGLE_SETTINGS_MODAL,
  TOGGLE_STATS_MODAL,
  TOGGLE_INFO_MODAL,
} from "../../types";

const Toolbar = () => {
  const { loadingPhotosList, loadingPhoto } = useContext(ApiContext);
  const { dispatch } = useContext(SettingsContext);

  if (loadingPhoto || loadingPhotosList) return null;

  return (
    <div className="toolbar-container">
      <IoIosStats
        className="stats-icon"
        onClick={() => dispatch({ type: TOGGLE_STATS_MODAL, payload: true })}
      />
      <IoMdSettings
        className="settings-icon"
        onClick={() => dispatch({ type: TOGGLE_SETTINGS_MODAL, payload: true })}
      />
      <AiFillInfoCircle
        className="instructions-icon"
        onClick={() => dispatch({ type: TOGGLE_INFO_MODAL, payload: true })}
      />
    </div>
  );
};

export default Toolbar;
