import toast from "react-hot-toast";
import ToastFailureText from "../../general/ToastFailureText";

export const generateToast = (success, displayedCity) => {
  if (!success) {
    const { correct: city, country } = displayedCity;
    toast.error(<ToastFailureText city={city} country={country} />, {
      duration: Infinity,
    });
  } else {
    toast.success("", { duration: Infinity });
  }
};
