import { useContext } from "react";
import { ApiContext } from "../../contexts/ApiContext";
import Choice from "./Choice";
import "../../styles/choices/Choices.css";

const Choices = () => {
  const { photosList, photoIndex, loadingPhoto } = useContext(ApiContext);
  const { choices, id: photoId } = photosList[photoIndex] || {};

  if (loadingPhoto || !choices) {
    return null;
  }

  return (
    <div className="choices">
      {choices.map((choice, index) => (
        <Choice choice={choice} key={index} photoId={photoId} />
      ))}
    </div>
  );
};

export default Choices;
