import { useContext } from "react";
import { SettingsContext } from "../../contexts/SettingsContext";
import "../../styles/toolbar/toolbar-modal.css";

const Modal = ({ content, closeModal }) => {
  const { darkMode } = useContext(SettingsContext);
  const preventCloseOnClick = (event) => event.stopPropagation();

  return (
    <div
      className={`toolbar-modal ${
        darkMode ? "modal-dark-mode" : "modal-light-mode"
      }`}
      onClick={preventCloseOnClick}
    >
      <div className="modal-close-button-container">
        <div className="modal-close-button" onClick={closeModal}>
          ✕
        </div>
      </div>
      {content}
    </div>
  );
};

export default Modal;
