import {
  DIRECTION_ARROWS,
  EARTH_RADIUS_KILOMETERS,
} from "../constants/general";

export const calculateDistance = (cityA, cityB) => {
  const { latitude: latA, longitude: lonA } = cityA;
  const { latitude: latB, longitude: lonB } = cityB;

  const φ1 = (latA * Math.PI) / 180;
  const φ2 = (latB * Math.PI) / 180;
  const Δφ = ((latB - latA) * Math.PI) / 180;
  const Δλ = ((lonB - lonA) * Math.PI) / 180;

  const a =
    Math.sin(Δφ / 2) * Math.sin(Δφ / 2) +
    Math.cos(φ1) * Math.cos(φ2) * Math.sin(Δλ / 2) * Math.sin(Δλ / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));

  const distance = EARTH_RADIUS_KILOMETERS * c;
  return Math.round(distance);
};

export const calculateBearing = (endPoint, startPoint) => {
  const { latitude: endLat, longitude: endLon } = endPoint;
  const { latitude: startLat, longitude: startLon } = startPoint;

  const bearingInRadians = Math.atan2(endLon - startLon, endLat - startLat);
  const bearingInDegrees = bearingInRadians * (180 / Math.PI);

  let coordinateIndex = Math.round(bearingInDegrees / 45);
  if (coordinateIndex < 0) {
    coordinateIndex = coordinateIndex + 8;
  }

  return DIRECTION_ARROWS[coordinateIndex];
};
