import { USER_RECORD } from "../../../constants/strings";
import "../../../styles/toolbar/stats-modal.css";
import {
  extractHardModeResults,
  formatResults,
} from "../../../utils/statistics";
import BarChart from "./BarChart";
import StatsSection from "./StatSection";
import StatSectionSeparator from "./StatSectionSeparator";

const StatsContent = () => {
  const userRecord = JSON.parse(localStorage.getItem(USER_RECORD)) || [];

  return (
    <div className="stats-container">
      <div className="stats-heading">STATISTICS</div>
      <div>
        <StatsSection heading="OVERALL" stats={formatResults(userRecord)} />
        <StatSectionSeparator />
        <StatsSection
          heading="HARD MODE"
          stats={formatResults(userRecord, true)}
        />
        <BarChart resultDistribution={extractHardModeResults(userRecord)} />
        <StatSectionSeparator />
        <StatsSection
          heading="EASY MODE"
          stats={formatResults(userRecord, false)}
        />
      </div>
    </div>
  );
};

export default StatsContent;
