import { useContext } from "react";
import GuessSection from "./GuessSection";
import "../../styles/guesses/guesses.css";
import {
  formatLocationText,
  addUnitToDistance,
  convertKmToMiles,
} from "../../utils/general";
import { SettingsContext } from "../../contexts/SettingsContext";
import { KM, MI } from "../../constants/strings";

const Guess = ({ city, countryCode, flag, distance, bearing }) => {
  const { distancesInMiles, darkMode } = useContext(SettingsContext);
  const formattedDistance =
    distance && (distancesInMiles ? convertKmToMiles(distance) : distance);
  const distanceUnit = distancesInMiles ? MI : KM;

  return (
    <div
      className={`guess-container ${
        darkMode ? "guess-container-dark-mode" : "guess-container-light-mode"
      }`}
    >
      <GuessSection text={formatLocationText(city, countryCode)} emoji={flag} />
      <GuessSection
        text={addUnitToDistance(formattedDistance, distanceUnit)}
        emoji={bearing}
        reverse
      />
    </div>
  );
};

export default Guess;
