import { useContext, useEffect, useState } from "react";
import toast, { Toaster, resolveValue } from "react-hot-toast";
import { ApiContext } from "../../contexts/ApiContext";
import {
  CLOSE_ANY_OPEN_MODAL,
  INCREMENT_PHOTO_INDEX,
  RESET_GUESSES,
  SET_LOADING_PHOTO,
} from "../../types";
import "../../styles/general/custom-toast.css";
import { SettingsContext } from "../../contexts/SettingsContext";
import { SUCCESS_MESSAGES } from "../../constants/general";

const CustomToast = () => {
  const { dispatch } = useContext(ApiContext);
  const { dispatch: settingsDispatch, darkMode } = useContext(SettingsContext);
  const [successMessage, setSuccessMessage] = useState("");

  useEffect(() => {
    setSuccessMessage(
      SUCCESS_MESSAGES[Math.floor(Math.random() * SUCCESS_MESSAGES.length)]
    );
  }, []);

  const handleClose = (t) => {
    toast.dismiss(t.id);
    dispatch({ type: INCREMENT_PHOTO_INDEX });
    dispatch({ type: SET_LOADING_PHOTO });
    dispatch({ type: RESET_GUESSES });
    settingsDispatch({ type: CLOSE_ANY_OPEN_MODAL });
  };

  return (
    <Toaster>
      {(t) => {
        const successToast = t.type === "success";
        return (
          <div
            style={{ opacity: t.visible ? 1 : 0 }}
            className={`toast-container ${
              darkMode
                ? "toast-container-dark-mode"
                : "toast-container-light-mode"
            }`}
          >
            <div>
              {successToast ? <span>🎉</span> : resolveValue(t.message, t)}
            </div>
            {successToast && <div>{successMessage}</div>}
            <div
              onClick={() => handleClose(t)}
              className="close-button"
              title="Close and load next question"
            >
              ✕
            </div>
          </div>
        );
      }}
    </Toaster>
  );
};

export default CustomToast;
