import { createContext, useEffect, useReducer } from "react";
import { INITIAL_SETTINGS } from "../constants/initial-state";
import { settingsReducer } from "../reducers";
import { TOGGLE_DARK_MODE } from "../types";
import { USER_SETTINGS } from "../constants/strings";

export const SettingsContext = createContext();

const SettingsProvider = ({ children }) => {
  const initialSettings =
    JSON.parse(localStorage.getItem(USER_SETTINGS)) || INITIAL_SETTINGS;
  const [state, dispatch] = useReducer(settingsReducer, initialSettings);

  useEffect(() => {
    if (window.matchMedia("(prefers-color-scheme: dark)").addEventListener) {
      window
        .matchMedia("(prefers-color-scheme: dark)")
        .addEventListener("change", (event) => {
          if (event.matches) {
            dispatch({ type: TOGGLE_DARK_MODE, payload: true });
          }
        });

      if (window.matchMedia("(prefers-color-scheme: dark)").matches) {
        dispatch({ type: TOGGLE_DARK_MODE, payload: true });
      }

      return () => {
        window
          .matchMedia("(prefers-color-scheme: dark)")
          .removeEventListener("change", () => {});
      };
    }
  }, []);

  return (
    <SettingsContext.Provider value={{ dispatch, ...state }}>
      {children}
    </SettingsContext.Provider>
  );
};

export default SettingsProvider;
