import { useContext, useState } from "react";
import CountrySelect from "./CountrySelect";
import "../../../styles/choices/Choices.css";
import CityInput from "./CityInput";
import SubmitButton from "./SubmitButton";
import { ApiContext } from "../../../contexts/ApiContext";
import "../../../styles/select/inputs-container.css";
import CityNotFound from "./CityNotFound";
import { STANDARD } from "../../../constants/strings";
import { NUM_GUESSES } from "../../../constants/general";

const InputsContainer = () => {
  const [cityNotFound, setCityNotFound] = useState(false);
  const [cityInputFocus, setCityInputFocus] = useState(STANDARD);
  const {
    loadingPhotosList,
    loadingPhoto,
    numGuesses,
    submitClicked,
    distanceBeingUpdated,
  } = useContext(ApiContext);
  const inputsDisabled =
    submitClicked || numGuesses === NUM_GUESSES || distanceBeingUpdated;

  if (loadingPhoto || loadingPhotosList) return null;

  return (
    <div className="main-container">
      <CityNotFound cityNotFound={cityNotFound} />
      <div className="inputs-container">
        <CityInput
          setCityNotFound={setCityNotFound}
          cityInputFocus={cityInputFocus}
          setCityInputFocus={setCityInputFocus}
          disabled={inputsDisabled}
        />
        <CountrySelect
          setCityNotFound={setCityNotFound}
          setCityInputFocus={setCityInputFocus}
          disabled={inputsDisabled}
        />
        <SubmitButton disabled={inputsDisabled} />
      </div>
    </div>
  );
};

export default InputsContainer;
