import { useEffect } from "react";
import { SET_LOADING_IS_SLOW } from "../../../types";
import { API_CALL_MAX_TIME } from "../../../constants/api";

export const useLoaderTimeout = (dispatch, loadingPhotosList, loadingPhoto) => {
  useEffect(() => {
    const loaderTimeout = setTimeout(() => {
      (loadingPhotosList || loadingPhoto) &&
        dispatch({ type: SET_LOADING_IS_SLOW });
    }, API_CALL_MAX_TIME);

    return () => {
      clearTimeout(loaderTimeout);
    };
  }, [dispatch, loadingPhotosList, loadingPhoto]);
};
