import { useEffect } from "react";
import { getCityDetails } from "../../../api/apis";
import {
  SET_CITY_DETAILS,
  SET_CITY_DETAILS_FETCH_ERROR,
  SET_CITY_DETAILS_NOT_LOADING,
} from "../../../types";
import { CITY_NAME_MIN_LENGTH } from "../../../constants/general";

export const useFetchCityDetails = (
  dispatch,
  selectedCity,
  selectedCountry
) => {
  useEffect(() => {
    const fetchCoordinates = async (city, country) => {
      try {
        const response = await getCityDetails(city, country);
        const data = await response.json();
        dispatch({ type: SET_CITY_DETAILS, payload: data });
      } catch (err) {
        dispatch({ type: SET_CITY_DETAILS_FETCH_ERROR, payload: err });
      }
      dispatch({
        type: SET_CITY_DETAILS_NOT_LOADING,
        payload: `${city}-${country}`,
      });
    };
    if (selectedCity.length >= CITY_NAME_MIN_LENGTH && selectedCountry?.value) {
      fetchCoordinates(selectedCity, selectedCountry.value);
    }
  }, [selectedCity, selectedCountry, dispatch]);
};
