import { useContext } from "react";
import { CITY_NAME_MIN_LENGTH } from "../../../constants/general";
import ButtonLoader from "./ButtonLoader";
import { ApiContext } from "../../../contexts/ApiContext";
import { SET_SUBMIT_CLICKED } from "../../../types";
import { useSubmitValidCity } from "../../hooks/submit-button/useSubmitValidCity";
import "../../../styles/select/guess-button.css";

const SubmitButton = ({ disabled }) => {
  const state = useContext(ApiContext);
  const {
    dispatch,
    selectedCity,
    selectedCountry,
    cityDetailsLoading,
    submitClicked,
  } = state;

  const validSelection =
    selectedCity.length >= CITY_NAME_MIN_LENGTH && !!selectedCountry?.value;
  const buttonDisabled = !validSelection || disabled;
  const buttonClass = `guess-button ${buttonDisabled && "disabled"}`;

  useSubmitValidCity(state);

  const handleClick = () => {
    dispatch({ type: SET_SUBMIT_CLICKED, payload: true });
  };

  return (
    <button
      disabled={buttonDisabled}
      className={buttonClass}
      onClick={handleClick}
    >
      <div className="button-side-section">
        {submitClicked && cityDetailsLoading && <ButtonLoader />}
      </div>
      <div className="button-center-section">
        <span className="globe-emoji">🌎</span> Guess
      </div>
      <div className="button-side-section" />
    </button>
  );
};

export default SubmitButton;
