import { ESCAPE } from "../../constants/strings";
import Modal from "./Modal";
import "../../styles/toolbar/toolbar-modal.css";

const ModalContainer = ({ closeModal, content }) => {
  document.onkeydown = (event) => {
    if (event.key === ESCAPE) {
      closeModal();
    }
  };

  return (
    <div className="toolbar-modal-container" onClick={closeModal}>
      <Modal content={content} closeModal={closeModal} />
    </div>
  );
};

export default ModalContainer;
