import styled from "@emotion/styled";
import { Switch } from "@mui/material";

const GreenSwitch = styled(Switch)(() => ({
  "& .MuiSwitch-switchBase.Mui-checked": {
    color: "#0b6e45",
  },
  "& .MuiSwitch-switchBase.Mui-checked + .MuiSwitch-track": {
    backgroundColor: "#0b6e45",
  },
}));

const SettingsSection = ({
  title,
  description,
  checked,
  onChange,
  isSwitch,
  value,
}) => {
  return (
    <div className="section-switch-container">
      <div className="switch-container">
        <div>{title}</div>
        {isSwitch ? (
          <GreenSwitch checked={checked} onChange={onChange} />
        ) : (
          <div className="section-value">{value}</div>
        )}
      </div>
      <div className="switch-description">{description}</div>
    </div>
  );
};

export default SettingsSection;
