import { useEffect } from "react";
import _ from "lodash";
import { USER_RECORD } from "../../../constants/strings";
import { getPhotosList } from "../../../api/apis";
import { countUnique, removePlayed } from "../../../utils/general";
import { SET_NUM_RECORDS, SET_PHOTOS_LIST } from "../../../types";
import { BACKUP_PHOTOS_LIST } from "../../../data/photos";

export const useFetchPhotosList = (dispatch) => {
  useEffect(() => {
    const userRecord = JSON.parse(localStorage.getItem(USER_RECORD));
    const fetchPhotosList = async () => {
      try {
        const response = await getPhotosList();
        const photosList = await response.json();
        const formattedList = photosList.map(({ fields }) => fields);
        const allCities = formattedList.map(({ correct }) => correct);
        const allCountries = formattedList.map(({ country }) => country);
        const numCities = countUnique(allCities);
        const numCountries = countUnique(allCountries);
        dispatch({
          type: SET_NUM_RECORDS,
          payload: { numCities, numCountries },
        });
        const prunedList = removePlayed(formattedList, userRecord);
        const shuffledList = _.shuffle(
          prunedList.map((photo) => ({
            ...photo,
            choices: _.shuffle(photo.choices),
          }))
        );
        dispatch({ type: SET_PHOTOS_LIST, payload: shuffledList });
      } catch (err) {
        const backupPhotosList = removePlayed(BACKUP_PHOTOS_LIST, userRecord);
        dispatch({ type: SET_PHOTOS_LIST, payload: backupPhotosList });
      }
    };
    fetchPhotosList();
  }, [dispatch]);
};
