import { createContext, useReducer } from "react";
import { INITIAL_API_STATE } from "../constants/initial-state";
import { apiReducer } from "../reducers";
import { useFetchPhotosList } from "../components/hooks/api-hooks/useFetchPhotosList";
import { useFetchPhoto } from "../components/hooks/api-hooks/useFetchPhoto";
import { useFetchCityDetails } from "../components/hooks/api-hooks/useFetchCityDetails";
import { useLoaderTimeout } from "../components/hooks/api-hooks/useLoaderTimeout";

export const ApiContext = createContext();

const ApiContextProvider = ({ children }) => {
  const [state, dispatch] = useReducer(apiReducer, INITIAL_API_STATE);
  const {
    photosList,
    loadingPhotosList,
    loadingPhoto,
    photoIndex,
    selectedCity,
    selectedCountry,
  } = state;

  useFetchPhotosList(dispatch);
  useFetchPhoto(dispatch, photosList, photoIndex, loadingPhotosList);
  useFetchCityDetails(dispatch, selectedCity, selectedCountry);
  useLoaderTimeout(dispatch, loadingPhotosList, loadingPhoto);

  return (
    <ApiContext.Provider value={{ dispatch, ...state }}>
      {children}
    </ApiContext.Provider>
  );
};

export default ApiContextProvider;
