import PhotoContainer from "./PhotoContainer";
import AttributionText from "./attribution-text/AttributionText";
import { useState } from "react";
import PhotoModal from "./modal/PhotoModal";
import PhotoModalContent from "./modal/PhotoModalContent";
import CustomToast from "../general/CustomToast";

const Photo = ({ displayedPhoto }) => {
  const [isOpen, setIsOpen] = useState(false);
  const openModal = () => setIsOpen(true);
  const closeModal = () => setIsOpen(false);

  const imageSrc = displayedPhoto?.urls.regular;

  return (
    <PhotoContainer>
      <CustomToast />
      <PhotoModal openModal={openModal} imageSrc={imageSrc} />
      <AttributionText
        photoId={displayedPhoto?.id}
        photographerName={displayedPhoto?.user.name}
        photographerUrl={displayedPhoto?.user.links.html}
      />
      {isOpen && (
        <PhotoModalContent closeModal={closeModal} imageSrc={imageSrc} />
      )}
    </PhotoContainer>
  );
};

export default Photo;
