import {
  DISABLE_CHOICES,
  ENABLE_CHOICES,
  REVEAL_ANSWER,
  HIDE_ANSWER,
  TOGGLE_HARD_MODE,
  TOGGLE_DARK_MODE,
  TOGGLE_DISTANCES_IN_MILES,
  TOGGLE_SETTINGS_MODAL,
  TOGGLE_STATS_MODAL,
  TOGGLE_INFO_MODAL,
  CLOSE_ANY_OPEN_MODAL,
} from "../types";

export const settingsReducer = (state, action) => {
  const { type, payload } = action;
  switch (type) {
    case TOGGLE_HARD_MODE:
      return { ...state, hardMode: payload };
    case TOGGLE_DARK_MODE:
      return { ...state, darkMode: payload };
    case TOGGLE_DISTANCES_IN_MILES:
      return { ...state, distancesInMiles: payload };
    case DISABLE_CHOICES:
      return { ...state, disableChoices: true };
    case ENABLE_CHOICES:
      return { ...state, disableChoices: false };
    case REVEAL_ANSWER:
      return { ...state, revealAnswer: true };
    case HIDE_ANSWER:
      return { ...state, revealAnswer: false };
    case TOGGLE_SETTINGS_MODAL:
      return { ...state, settingsModalOpen: payload };
    case TOGGLE_STATS_MODAL:
      return { ...state, statsModalOpen: payload };
    case TOGGLE_INFO_MODAL:
      return { ...state, infoModalOpen: payload };
    case CLOSE_ANY_OPEN_MODAL:
      return {
        ...state,
        settingsModalOpen: false,
        infoModalOpen: false,
        statsModalOpen: false,
      };
    default:
      return state;
  }
};
