import {
  DISPATCH_EVERY_INTERVAL,
  NUM_GUESSES,
  PORTION_DISPATCHED_PER_INTERVAL,
} from "../../../constants/general";
import { USER_RECORD, USER_SETTINGS } from "../../../constants/strings";
import {
  FINALIZE_GUESS,
  SET_DISTANCE_BEING_UPDATED,
  SET_GUESS_DISTANCE,
} from "../../../types";
import { generateToast } from "./generate-toast";

const updateUserSettings = () => {
  const currentSettings = JSON.parse(localStorage.getItem(USER_SETTINGS));
  const updatedSettings = {
    ...currentSettings,
    infoModalOpen: false,
    statsModalOpen: true,
  };
  localStorage.setItem(USER_SETTINGS, JSON.stringify(updatedSettings));
};

const dispatchDistance = (dispatch, distance) => {
  dispatch({
    type: SET_GUESS_DISTANCE,
    payload: Math.round(distance),
  });
};

const finalizeDispatch = (dispatch, finalDistance = 0) => {
  dispatch({ type: FINALIZE_GUESS, payload: finalDistance });
  dispatch({ type: SET_DISTANCE_BEING_UPDATED, payload: false });
};

export const dispatchDistances = (
  dispatch,
  finalDistance,
  numGuesses,
  displayedCity,
  photoId
) => {
  const currentRecord = JSON.parse(localStorage.getItem(USER_RECORD)) || [];
  let intervalCount = 1;
  const distanceDispatchInterval = setInterval(() => {
    const distanceElapsed =
      finalDistance * intervalCount * PORTION_DISPATCHED_PER_INTERVAL;
    if (distanceElapsed <= finalDistance) {
      dispatchDistance(dispatch, distanceElapsed);
    } else {
      finalizeDispatch(dispatch, finalDistance);
      if (numGuesses === NUM_GUESSES - 1) {
        generateToast(false, displayedCity);
        currentRecord.push({
          id: photoId,
          correct: false,
          hardMode: true,
          numGuesses: numGuesses + 1,
        });
        localStorage.setItem(USER_RECORD, JSON.stringify(currentRecord));
        updateUserSettings();
      }
      clearInterval(distanceDispatchInterval);
    }
    intervalCount += 1;
  }, DISPATCH_EVERY_INTERVAL);
};

export const reverseDispatchDistances = (
  dispatch,
  startDistance,
  numGuesses,
  photoId
) => {
  const currentRecord = JSON.parse(localStorage.getItem(USER_RECORD)) || [];
  let intervalCount = 1;
  const distanceDispatchInterval = setInterval(() => {
    const distanceRemaining =
      startDistance * (1 - intervalCount * PORTION_DISPATCHED_PER_INTERVAL);
    if (distanceRemaining >= 0) {
      dispatchDistance(dispatch, distanceRemaining);
    } else {
      finalizeDispatch(dispatch);
      generateToast(true);
      clearInterval(distanceDispatchInterval);
      currentRecord.push({
        id: photoId,
        correct: true,
        hardMode: true,
        numGuesses: numGuesses + 1,
      });
      localStorage.setItem(USER_RECORD, JSON.stringify(currentRecord));
      updateUserSettings();
    }
    intervalCount += 1;
  }, DISPATCH_EVERY_INTERVAL);
};
