import { useEffect } from "react";
import {
  INCREMENT_PHOTO_INDEX,
  SET_DISPLAYED_PHOTO,
  SET_LIMITED_REACHED,
} from "../../../types";
import { getPhoto } from "../../../api/apis";

export const useFetchPhoto = (
  dispatch,
  photosList,
  photoIndex,
  loadingPhotosList
) => {
  useEffect(() => {
    if (photoIndex === photosList.length && !loadingPhotosList) {
      return dispatch({ type: SET_LIMITED_REACHED });
    }

    const { id: unsplashPhotoId } = photosList[photoIndex] || {};
    const loadPhoto = async () => {
      try {
        const response = await getPhoto(unsplashPhotoId);
        const data = await response.json();
        if (response.status !== 200) {
          throw new Error();
        } else {
          dispatch({ type: SET_DISPLAYED_PHOTO, payload: data });
        }
      } catch (err) {
        dispatch({ type: INCREMENT_PHOTO_INDEX });
      }
    };
    unsplashPhotoId && loadPhoto();
  }, [photosList, photoIndex, loadingPhotosList, dispatch]);
};
